#include "audio_decoder.hpp"
#include <QAudioBuffer>
#include <QDebug>

namespace Rina::Core {

AudioDecoder::AudioDecoder(int clipId, const QUrl &source, QObject *parent) : QObject(parent), m_clipId(clipId) {

    m_decoder = new QAudioDecoder(this);

    // プロジェクト標準の音声フォーマット（48kHz, Stereo, Float）
    QAudioFormat format;
    format.setSampleRate(48000);
    format.setChannelCount(2);
    format.setSampleFormat(QAudioFormat::Float);

    m_decoder->setAudioFormat(format);
    m_decoder->setSource(source);

    // 修正: ループ時のデコーダリセット処理を削除。
    // AudioDecoderはファイルを一度だけ全読み込みし、メモリ上に保持し続ける設計とします。
    // これにより、デコードが遅い場合でもリセットされず、完了次第音が鳴るようになります。

    connect(m_decoder, &QAudioDecoder::bufferReady, this, &AudioDecoder::onBufferReady);
    connect(m_decoder, &QAudioDecoder::finished, this, &AudioDecoder::onFinished);
    connect(m_decoder, QOverload<QAudioDecoder::Error>::of(&QAudioDecoder::error), this, [this](QAudioDecoder::Error error) {
        qWarning() << "[AudioDecoder] Error occurred:" << error;
        onError(error);
    });

    qDebug() << "[AudioDecoder] Decoding started for clip" << clipId << source;
    m_decoder->start();
}

void AudioDecoder::seek(qint64 ms) { emit seekRequested(ms); }

void AudioDecoder::onBufferReady() {
    QAudioBuffer buffer = m_decoder->read();
    if (!buffer.isValid())
        return;

    const int sampleCount = buffer.sampleCount();
    const auto fmt = buffer.format();

    // 初回のみフォーマットをログ出力
    static bool loggedFormat = false;
    if (!loggedFormat) {
        qDebug() << "[AudioDecoder] Received buffer format:" << fmt;
        loggedFormat = true;
    }

    // フォーマットに応じてFloatへ変換して格納
    if (fmt.sampleFormat() == QAudioFormat::Float) {
        const float *data = buffer.constData<float>();
        if (data)
            m_fullAudioData.insert(m_fullAudioData.end(), data, data + sampleCount);
    } else if (fmt.sampleFormat() == QAudioFormat::Int16) {
        const qint16 *data = buffer.constData<qint16>();
        if (data) {
            m_fullAudioData.reserve(m_fullAudioData.size() + sampleCount);
            for (int i = 0; i < sampleCount; ++i) {
                // 16bit int -> float
                m_fullAudioData.push_back(static_cast<float>(data[i]) / 32768.0f);
            }
        }
    } else {
        qWarning() << "[AudioDecoder] Unsupported sample format:" << fmt.sampleFormat();
    }
}

void AudioDecoder::onFinished() {
    m_isReady = true;
    qDebug() << "[AudioDecoder] Decoding finished. Total samples:" << m_fullAudioData.size();
    emit ready();
}

void AudioDecoder::onError(QAudioDecoder::Error error) { qWarning() << "[AudioDecoder] Error occurred:" << error << m_decoder->errorString(); }

std::vector<float> AudioDecoder::getSamples(double startTime, int count) {
    // 48kHz, Stereo (2ch)
    // startTime (秒) * 48000 (サンプル/秒) * 2 (チャンネル)
    size_t startIdx = static_cast<size_t>(startTime * 48000 * 2);

    // 偶数アライメント（ステレオのL/Rがずれないように補正）
    if (startIdx % 2 != 0)
        startIdx--;

    if (startIdx >= m_fullAudioData.size()) {
        return std::vector<float>(count, 0.0f);
    }

    size_t available = m_fullAudioData.size() - startIdx;
    size_t actualCount = std::min(static_cast<size_t>(count), available);

    std::vector<float> result(m_fullAudioData.begin() + startIdx, m_fullAudioData.begin() + startIdx + actualCount);

    // 足りない分は0埋め（無音）
    if (result.size() < static_cast<size_t>(count)) {
        result.resize(count, 0.0f);
    }

    return result;
}

} // namespace Rina::Core

#include "effect_registry.hpp"
#include <QCoreApplication>
#include <QDebug>
#include <QDir>
#include <QDirIterator>
#include <QFile>
#include <QFileInfo>
#include <QJsonDocument>
#include <QJsonObject>
#include <QUrl>

namespace Rina::Core {

void initializeStandardEffects() {
    // 外部JSON経由で読み込むため、何もしない
}

void EffectRegistry::loadEffectsFromDirectory(const QString &path) {
    QDir dir(path);
    if (!dir.exists()) {
        qWarning().noquote() << "Effect directory not found:" << path;
        return;
    }

    // *.json ファイルをサブディレクトリを含めて検索
    QDirIterator it(path, {"*.json"}, QDir::Files, QDirIterator::Subdirectories);

    while (it.hasNext()) {
        QFile file(it.next());
        if (!file.open(QIODevice::ReadOnly))
            continue;

        QJsonParseError error;
        // 最適化: 巨大なJSONの場合はメモリマップドファイル化を検討
        const auto data = file.readAll();
        const auto doc = QJsonDocument::fromJson(data, &error);

        if (error.error != QJsonParseError::NoError || !doc.isObject()) {
            qWarning().noquote() << "Invalid JSON in" << file.fileName() << ":" << error.errorString();
            continue;
        }

        QJsonObject obj = doc.object();
        QString id = obj["id"].toString();
        QString name = obj["name"].toString();
        QString category = obj["category"].toString("filter");
        QString qmlFileName = obj["qml"].toString();
        QVariantMap params = obj["params"].toObject().toVariantMap();
        QVariantMap uiDef = obj["ui"].toObject().toVariantMap();

        if (id.isEmpty() || name.isEmpty() || qmlFileName.isEmpty()) {
            qWarning().noquote() << "不完全なエフェクト定義のためスキップ:" << file.fileName() << "。";
            if (id.isEmpty()) {
                qWarning().noquote() << "  - 理由: 'id' フィールドが空または存在しません。";
            }
            if (name.isEmpty()) {
                qWarning().noquote() << "  - 理由: 'name' フィールドが空または存在しません。";
            }
            if (qmlFileName.isEmpty()) {
                qWarning().noquote() << "  - 理由: 'qml' フィールドが空または存在しません。";
            }
            qWarning().noquote() << "  - 解析されたJSON内容:" << doc.toJson(QJsonDocument::Compact);
            continue;
        }

        EffectMetadata meta;
        meta.id = id;
        meta.name = name;
        meta.category = category;
        meta.defaultParams = params;
        meta.uiDefinition = uiDef;

        // qrc: で始まる場合は絶対パスとしてそのまま使用
        if (qmlFileName.startsWith("qrc:")) {
            meta.qmlSource = qmlFileName;
            registerEffect(meta);
            qDebug().noquote() << "外部エフェクトをロード:" << name << "(" << id << ") from" << file.fileName();
            continue;
        }

        // QMLファイルの絶対パスを解決 (JSONファイルからの相対パスとして処理)
        QFileInfo jsonInfo(file.fileName());
        QString absoluteQmlPath = jsonInfo.absoluteDir().filePath(qmlFileName);

        if (QFile::exists(absoluteQmlPath)) {
            meta.qmlSource = QUrl::fromLocalFile(absoluteQmlPath).toString();
        } else {
            qWarning() << "参照されているQMLファイルが見つかりません。エフェクト:" << id << "パス:" << absoluteQmlPath;
            continue;
        }

        registerEffect(meta);
        qDebug().noquote() << "外部エフェクトをロード:" << name << "(" << id << ") from" << file.fileName();
    }
}

} // namespace Rina::Core

#include "../../engine/timeline/ecs.hpp"
#include "../../scripting/mod_engine.hpp"
#include "effect_registry.hpp"
#include "rina_context.hpp"
#include "settings_manager.hpp"
#include "timeline_controller.hpp"
#include "video_encoder.hpp"
#include "video_frame_provider.hpp"
#include "video_frame_store.hpp"
#include "window_manager.hpp"
#include <QApplication>
#include <QIcon>
#include <QPixmap>
#include <QQmlApplicationEngine>
#include <QQmlContext>
#include <QQuickStyle> // 追加
#include <QQuickWindow>
#include <QTimer>
#include <lua.hpp>

int main(int argc, char *argv[]) {
    // --- マルチプラットフォーム対応 ハードウェアデコード設定 ---
    // 1. バックエンドをFFmpegに固定（Rinaのロジック依存のため）
    qputenv("QT_MEDIA_BACKEND", "ffmpeg");

    // 2. 優先するHWデコーダリストを指定（環境依存のドライバ名は指定しない）
    // Linux(VAAPI/VDPAU/CUDA), Windows(D3D11VA/DXVA2), macOS(VideoToolbox) を網羅
    qputenv("QT_FFMPEG_DECODING_HW_DEVICE_TYPES", "cuda,vaapi,vdpau,videotoolbox,d3d11va,dxva2");

    // 1. アプリケーション初期化
#if QT_VERSION < QT_VERSION_CHECK(6, 0, 0)
    QCoreApplication::setAttribute(Qt::AA_EnableHighDpiScaling);
#endif
    QApplication app(argc, argv);
    app.setApplicationName("Rina");

    // 【追加】アプリケーションアイコンの設定
    // Qtのリソースシステム (:prefix) から読み込みます
    // SVGをアイコンに設定すると、ウィンドウマネージャ(KDE/Wayland)が適切にラスタライズしてくれます
    app.setWindowIcon(QIcon(":/assets/icon.svg"));

    // 設定のロード(インスタンス取得時にloadされる)
    Rina::Core::SettingsManager::instance().settings();

    // エフェクトレジストリの初期化
    Rina::Core::initializeStandardEffects();

    // --- Lua MODエンジンの初期化 (Phase 1 & 2) ---
    auto &modEngine = Rina::Scripting::ModEngine::instance();
    // ECSのインスタンス（g_ecsState）のアドレスをLuaに渡す
    void *ecsPtr = Rina::Engine::Timeline::ECS::instance().getInternalStatePtr();
    modEngine.initialize(ecsPtr);

    // プラグインのロード
    modEngine.loadPlugins();

    // Luaフック用のタイマー (約60FPSで同期)
    QTimer luaHookTimer;
    QObject::connect(&luaHookTimer, &QTimer::timeout, [&modEngine]() { modEngine.onUpdate(); });
    luaHookTimer.start(16);

    // 外部リソースのロード
    QString appDir = QCoreApplication::applicationDirPath();

    // 1. Filters (./effects)
    Rina::Core::EffectRegistry::instance().loadEffectsFromDirectory(appDir + "/effects");

    // 2. Objects (./objects)
    Rina::Core::EffectRegistry::instance().loadEffectsFromDirectory(appDir + "/objects");

    // 1. スタイルの強制適用 (KDE Plasma Native)
    // これにより、システムの色設定（ダークモード等）が自動的にQMLに反映される
    // 削除: Windows等で "org.kde.desktop" がない場合にクラッシュする原因となる
    // Qtデフォルトの自動判定に任せることで、OSごとのネイティブスタイル(WindowsVista等)が適用される
    QQuickStyle::setFallbackStyle("Fusion"); // Fallback for environments without a native style

    QQmlApplicationEngine engine;

    // VideoFrameProviderの登録
    auto *videoFrameStore = new Rina::Core::VideoFrameStore(&app);
    engine.addImageProvider("videoFrame", new Rina::Core::VideoFrameProvider(videoFrameStore));
    engine.rootContext()->setContextProperty("videoFrameStore", videoFrameStore);

    // VideoEncoderをQMLでインスタンス化可能な型として登録
    qmlRegisterType<Rina::Core::VideoEncoder>("Rina.Core", 1, 0, "VideoEncoder");

    // SettingsManager の登録
    engine.rootContext()->setContextProperty("SettingsManager", &Rina::Core::SettingsManager::instance());

    // TimelineBridge の登録
    // アプリケーション生存期間中維持されるインスタンスを作成
    auto *timelineController = new Rina::UI::TimelineController(&app);
    engine.rootContext()->setContextProperty("TimelineBridge", timelineController);

    // TimelineControllerにVideoFrameStoreを渡す
    timelineController->setVideoFrameStore(videoFrameStore);

    // WindowManager をQMLから触れるように公開
    engine.rootContext()->setContextProperty("WindowManager", static_cast<QObject *>(&Rina::UI::WindowManager::instance()));

    // ウィンドウ生成（バックグラウンドで生成）
    Rina::UI::WindowManager::instance().spawnInitialWindows(&engine);

    return app.exec();
}

#include "project_serializer.hpp"
#include "effect_registry.hpp"
#include "project_service.hpp"
#include "settings_manager.hpp"
#include "timeline_service.hpp"
#include <QDebug>
#include <QFile>
#include <QJsonArray>
#include <QJsonDocument>
#include <QJsonObject>
#include <QUrl>

namespace Rina::Core {

bool ProjectSerializer::save(const QString &fileUrl, const UI::TimelineService *timeline, const UI::ProjectService *project, QString *errorMessage) {
    QString path = QUrl(fileUrl).toLocalFile();
    if (path.isEmpty())
        path = fileUrl;

    QJsonObject root;
    QJsonObject settings;
    settings["width"] = project->width();
    settings["height"] = project->height();
    settings["fps"] = project->fps();
    settings["totalFrames"] = project->totalFrames();
    root["settings"] = settings;

    // --- シーン情報の保存 ---
    QJsonArray scenesArray;
    for (const auto &scene : timeline->getAllScenes()) {
        QJsonObject sObj;
        sObj["id"] = scene.id;
        sObj["name"] = scene.name;
        sObj["width"] = scene.width;
        sObj["height"] = scene.height;
        sObj["fps"] = scene.fps;
        sObj["totalFrames"] = scene.totalFrames;
        sObj["start"] = scene.startFrame;
        sObj["duration"] = scene.durationFrames;
        scenesArray.append(sObj);
    }
    root["scenes"] = scenesArray;

    // --- 全シーンのクリップをフラットに保存 ---
    QJsonArray clipsArray;
    for (const auto &scene : timeline->getAllScenes()) {
        for (const auto &clip : scene.clips) {
            QJsonObject clipObj;
            clipObj["id"] = clip.id;
            clipObj["sceneId"] = clip.sceneId; // シーンIDを保存
            clipObj["type"] = clip.type;
            clipObj["start"] = clip.startFrame;
            clipObj["duration"] = clip.durationFrames;
            clipObj["layer"] = clip.layer;

            QJsonArray effArray;
            for (const auto *eff : clip.effects) {
                QJsonObject eObj;
                eObj["id"] = eff->id();
                eObj["name"] = eff->name();
                eObj["enabled"] = eff->isEnabled();
                eObj["params"] = QJsonObject::fromVariantMap(eff->params());
                eObj["keyframes"] = QJsonObject::fromVariantMap(eff->keyframeTracks());
                effArray.append(eObj);
            }
            clipObj["effects"] = effArray;
            clipsArray.append(clipObj);
        }
    }
    root["clips"] = clipsArray;

    QFile file(path);
    if (!file.open(QIODevice::WriteOnly)) {
        if (errorMessage)
            *errorMessage = "書き込み用にファイルを開けませんでした: " + file.errorString();
        return false;
    }
    if (file.write(QJsonDocument(root).toJson()) == -1) {
        if (errorMessage)
            *errorMessage = "ファイルへの書き込みに失敗しました: " + file.errorString();
        return false;
    }
    return true;
}

bool ProjectSerializer::load(const QString &fileUrl, UI::TimelineService *timeline, UI::ProjectService *project, QString *errorMessage) {
    QString path = QUrl(fileUrl).toLocalFile();
    if (path.isEmpty())
        path = fileUrl;

    QFile file(path);
    if (!file.open(QIODevice::ReadOnly)) {
        if (errorMessage)
            *errorMessage = "読み込み用にファイルを開けませんでした: " + file.errorString();
        return false;
    }

    QJsonParseError error;
    QJsonDocument doc = QJsonDocument::fromJson(file.readAll(), &error);
    if (doc.isNull()) {
        if (errorMessage)
            *errorMessage = "JSONの解析に失敗しました: " + error.errorString();
        return false;
    }
    QJsonObject root = doc.object();

    // --- 1. 一時的な構造体にパース (検証フェーズ) ---

    // Project Settings
    bool hasSettings = root.contains("settings");
    auto defaults = Rina::Core::SettingsManager::instance().settings();
    int pWidth = defaults.value("defaultProjectWidth", 1920).toInt();
    int pHeight = defaults.value("defaultProjectHeight", 1080).toInt();
    int pTotalFrames = defaults.value("defaultProjectFrames", 300).toInt();
    double pFps = defaults.value("defaultProjectFps", 60.0).toDouble();

    if (hasSettings) {
        QJsonObject s = root["settings"].toObject();
        pWidth = s["width"].toInt(pWidth);
        pHeight = s["height"].toInt(pHeight);
        pFps = s["fps"].toDouble(pFps);
        pTotalFrames = s["totalFrames"].toInt(pTotalFrames);
    }

    // Scenes (読み込み)
    QList<UI::SceneData> tempScenes;
    int maxSceneId = 0;
    if (root.contains("scenes")) {
        QJsonArray scenesArray = root["scenes"].toArray();
        for (const auto &val : scenesArray) {
            QJsonObject s = val.toObject();
            UI::SceneData scene;
            scene.id = s["id"].toInt();
            scene.name = s["name"].toString();
            scene.width = s["width"].toInt(pWidth);
            scene.height = s["height"].toInt(pHeight);
            scene.fps = s["fps"].toDouble(pFps);
            scene.totalFrames = s["totalFrames"].toInt(pTotalFrames);
            scene.startFrame = s["start"].toInt(0);
            scene.durationFrames = s["duration"].toInt(0);
            tempScenes.append(scene);
            if (scene.id > maxSceneId)
                maxSceneId = scene.id;
        }
    } else {
        // 旧形式互換: デフォルトシーンを作成
        UI::SceneData rootScene;
        rootScene.id = 0;
        rootScene.name = "Root";
        tempScenes.append(rootScene);
    }

    // Clips
    QList<UI::ClipData> tempClips;
    int tempMaxId = 0;

    if (root.contains("clips")) {
        QJsonArray clipsArray = root["clips"].toArray();
        for (const auto &val : clipsArray) {
            QJsonObject c = val.toObject();
            UI::ClipData clip;
            clip.id = c["id"].toInt();
            clip.sceneId = c["sceneId"].toInt(0); // デフォルトは0
            if (clip.id > tempMaxId)
                tempMaxId = clip.id;
            clip.type = c["type"].toString();
            clip.startFrame = c["start"].toInt();
            clip.durationFrames = c["duration"].toInt();
            clip.layer = c["layer"].toInt();

            if (c.contains("effects")) {
                QJsonArray effArr = c["effects"].toArray();
                for (const auto &ev : effArr) {
                    QJsonObject eObj = ev.toObject();
                    QString effId = eObj["id"].toString();
                    EffectMetadata meta = EffectRegistry::instance().getEffect(effId);

                    // 中断した場合にタイムラインによって自動削除されるのを防ぐため、最初は親なしで作成
                    // メタデータからUI定義を取得、なければ空
                    auto *eff = new UI::EffectModel(effId, eObj["name"].toString(), eObj["params"].toObject().toVariantMap(), meta.qmlSource, meta.uiDefinition, nullptr);
                    eff->setEnabled(eObj["enabled"].toBool(true));
                    if (eObj.contains("keyframes"))
                        eff->setKeyframeTracks(eObj["keyframes"].toObject().toVariantMap());

                    clip.effects.append(eff);
                }
            }
            tempClips.append(clip);
        }
    }

    // --- 2. 変更を適用 (コミットフェーズ) ---

    if (hasSettings) {
        project->setWidth(pWidth);
        project->setHeight(pHeight);
        project->setFps(pFps);
        project->setTotalFrames(pTotalFrames);
    }

    // クリップを各シーンに分配
    for (auto &clip : tempClips) {
        for (auto *eff : clip.effects) {
            eff->setParent(timeline); // 所有権を移譲
            QObject::connect(eff, &UI::EffectModel::keyframeTracksChanged, timeline, &UI::TimelineService::clipsChanged);
        }

        // 対応するシーンを探して追加
        bool added = false;
        for (auto &scene : tempScenes) {
            if (scene.id == clip.sceneId) {
                scene.clips.append(clip);
                added = true;
                break;
            }
        }
        // シーンが見つからない場合はルート(0)または先頭に追加
        if (!added && !tempScenes.isEmpty()) {
            tempScenes[0].clips.append(clip);
        }
    }

    timeline->setScenes(tempScenes);
    timeline->setNextClipId(tempMaxId + 1);
    timeline->setNextSceneId(maxSceneId + 1);
    QMetaObject::invokeMethod(timeline, "clipsChanged");

    return true;
}
} // namespace Rina::Core

#include "settings_manager.hpp"
#include <QCoreApplication>
#include <QDebug>
#include <QDir>
#include <QFile>
#include <QFileInfo>
#include <QJsonDocument>
#include <QJsonObject>
