// コンストラクタ定義
WindowManager::WindowManager(QObject *parent) : QObject(parent) {}

// 実装: シングルトンインスタンス
WindowManager &WindowManager::instance() {
    static WindowManager inst(nullptr);
    return inst;
}

void WindowManager::spawnInitialWindows(QQmlEngine *engine) {
    m_engine = engine;

    // プロジェクトランチャーのみを表示
    QQmlComponent component(engine, QUrl("qrc:/qt/qml/Rina/ui/qml/ProjectLauncherWindow.qml"));
    QObject *obj = component.create();

    if (component.status() != QQmlComponent::Ready) {
        qWarning() << "ProjectLauncherWindowの作成に失敗:" << component.errorString();
        // フォールバック: 従来通りすぐに編集画面を開く
        spawnWindow(engine, "main", "qrc:/qt/qml/Rina/ui/qml/MainWindow.qml", "Rina Main Preview", 640, 480, 100, 100, true);
        spawnWindow(engine, "timeline", "qrc:/qt/qml/Rina/ui/qml/TimelineWindow.qml", "Timeline", 1280, 300, 100, 600, true);
        spawnWindow(engine, "objectSettings", "qrc:/qt/qml/Rina/ui/qml/SettingDialog.qml", "Object Settings", 400, 600, 800, 420, false);
        return;
    }

    QQuickWindow *launcher = qobject_cast<QQuickWindow *>(obj);
    if (launcher) {
        // プロジェクトが選択されたら、メインウィンドウを開く
        QObject::connect(launcher, SIGNAL(projectSelected(QString, int, int, double, int)), this, SLOT(onProjectSelected(QString, int, int, double, int)));
        registerWindow("launcher", launcher);
        launcher->show();
    } else {
        qWarning() << "ProjectLauncherWindowはQQuickWindowではありません";
    }
}

void WindowManager::onProjectSelected(const QString &path, int w, int h, double fps, int frames) {
    if (!m_engine) {
        qWarning() << "onProjectSelectedでQMLエンジンが利用できません";
        return;
    }

    // ランチャーを閉じる
    QPointer<QQuickWindow> launcher = m_windows.value("launcher");
    if (launcher) {
        launcher->close();
    }

    // プロジェクト設定を反映してメインウィンドウを開く
    spawnWindow(m_engine, "main", "qrc:/qt/qml/Rina/ui/qml/MainWindow.qml", "Rina Main Preview", 640, 480, 100, 100, true);
    spawnWindow(m_engine, "timeline", "qrc:/qt/qml/Rina/ui/qml/TimelineWindow.qml", "Timeline", 1280, 300, 100, 600, true);
    spawnWindow(m_engine, "projectSettings", "qrc:/qt/qml/Rina/ui/qml/ProjectSettingsWindow.qml", "Project Settings", 450, 250, 800, 100, false);
    spawnWindow(m_engine, "objectSettings", "qrc:/qt/qml/Rina/ui/qml/SettingDialog.qml", "Object Settings", 400, 600, 800, 420, false);
    spawnWindow(m_engine, "systemSettings", "qrc:/qt/qml/Rina/ui/qml/SystemSettingsWindow.qml", "System Settings", 600, 500, 200, 200, false);
    spawnWindow(m_engine, "sceneSettings", "qrc:/qt/qml/Rina/ui/qml/SceneSettingsWindow.qml", "Scene Settings", 450, 300, 300, 200, false);

    // 設定の反映
    QObject *bridge = m_engine->rootContext()->contextProperty("TimelineBridge").value<QObject *>();
    if (bridge) {
        if (!path.isEmpty()) {
            QMetaObject::invokeMethod(bridge, "loadProject", Q_ARG(QString, path));
        } else {
            QObject *project = bridge->property("project").value<QObject *>();
            if (project) {
                project->setProperty("width", w);
                project->setProperty("height", h);
                project->setProperty("fps", fps);
                project->setProperty("totalFrames", frames);
            }
        }
    }
}

void WindowManager::spawnWindow(QQmlEngine *engine, const QString &id, const QString &urlStr, const QString &title, int w, int h, int x, int y, bool visible) {
    if (!engine) {
        qWarning() << "WindowManager: QMLエンジンがnullです！";
        return;
    }

    QQmlComponent comp(engine, QUrl(urlStr));
    if (comp.status() != QQmlComponent::Ready) {
        qWarning() << "QMLエラー (" << title << "):" << comp.errorString();
        return;
    }

    QObject *obj = comp.create();
    if (auto win = qobject_cast<QQuickWindow *>(obj)) {
        win->setTitle(title);
        win->resize(w, h);
        win->setX(x);
        win->setY(y);
        registerWindow(id, win);
        if (visible)
            win->show();
        else
            win->hide();
    } else {
        // QQuickWindowではなかった場合 (View3D直置きなど)、ウィンドウを作る
        auto window = new QQuickWindow();
        window->setTitle(title);
        window->resize(w, h);
        window->setX(x);
        window->setY(y);

        auto item = qobject_cast<QQuickItem *>(obj);
        if (item) {
            item->setParentItem(window->contentItem());
        }
        registerWindow(id, window);
        if (visible)
            window->show();
        else
            window->hide();
    }
}

void WindowManager::registerWindow(const QString &id, QQuickWindow *win) {
    m_windows[id] = win;

    // ユーザーが×で閉じたり、hide/showした場合の同期
    connect(win, &QQuickWindow::visibleChanged, this, [this, id]() { emitVisibilityChanged(id); });
    connect(win, &QObject::destroyed, this, [this, id]() {
        m_windows.remove(id);
        emitVisibilityChanged(id);
    });

    // メインが閉じられたら「全終了」
    if (id == "main") {
        connect(win, &QQuickWindow::closing, this, [this](QQuickCloseEvent *e) {
            Q_UNUSED(e);
            requestQuit();
        });
    }

    emitVisibilityChanged(id);
}

void WindowManager::emitVisibilityChanged(const QString &id) {
    if (id == "timeline")
        emit timelineVisibleChanged();
    if (id == "projectSettings")
        emit projectSettingsVisibleChanged();
    if (id == "objectSettings")
        emit objectSettingsVisibleChanged();
    if (id == "systemSettings")
        emit systemSettingsVisibleChanged();
}

bool WindowManager::isVisible(const QString &id) const {
    QPointer<QQuickWindow> w = m_windows.value(id);
    return w ? w->isVisible() : false;
}
void WindowManager::setVisible(const QString &id, bool visible) {
    QPointer<QQuickWindow> w = m_windows.value(id);
    if (!w)
        return;
    if (visible)
        w->show();
    else
        w->hide();
    if (visible) {
        w->raise();
        w->requestActivate();
    }
}
void WindowManager::toggleVisible(const QString &id) { setVisible(id, !isVisible(id)); }
void WindowManager::raiseWindow(const QString &id) {
    QPointer<QQuickWindow> w = m_windows.value(id);
    if (!w)
        return;
    w->show();
    w->raise();
    w->requestActivate();
}

QObject *WindowManager::getWindow(const QString &id) const { return m_windows.value(id); }

void WindowManager::requestQuit() {
    // 全Windowを閉じる（main自身も含めてOK）
    for (auto it = m_windows.begin(); it != m_windows.end(); ++it) {
        if (it.value())
            it.value()->close();
    }
    QCoreApplication::quit();
}

bool WindowManager::timelineVisible() const { return isVisible("timeline"); }
void WindowManager::setTimelineVisible(bool v) { setVisible("timeline", v); }
bool WindowManager::projectSettingsVisible() const { return isVisible("projectSettings"); }
void WindowManager::setProjectSettingsVisible(bool v) { setVisible("projectSettings", v); }
bool WindowManager::objectSettingsVisible() const { return isVisible("objectSettings"); }
void WindowManager::setObjectSettingsVisible(bool v) { setVisible("objectSettings", v); }
bool WindowManager::systemSettingsVisible() const { return isVisible("systemSettings"); }
void WindowManager::setSystemSettingsVisible(bool v) { setVisible("systemSettings", v); }
} // namespace Rina::UI

import QtQml 2.15
import QtQuick 2.15
import QtQuick3D 6.0
import "common" as Common
import "common/Logger.js" as Logger

Item {
    id: root

    // レイヤーの表示状態を取得する関数（外部から注入される）
    property var getLayerVisible: function(layer) {
        return true;
    }
    readonly property int hiddenZ: -9999
    // Component cache to prevent redundant Qt.createComponent calls
    property var _componentCache: ({
    })

    function getCachedComponent(url) {
        if (_componentCache[url])
            return _componentCache[url];

        var c = Qt.createComponent(url, Component.Asynchronous);
        _componentCache[url] = c;
        return c;
    }

    anchors.fill: parent

    // 2Dレンダー（sourceItem/effects/ShaderEffectSource）を必ずQQuickWindow配下に置くためのホスト
    // visible:false でもWindow配下に居ればSceneGraph/Timerが正常に動く
    // 重要:
    // visible:false は SceneGraph から外れる → ShaderEffectSource の更新が止まりやすい。
    // 表示を消したいだけなら visible:true のまま opacity:0 に寄せる。
    Item {
        id: offscreenRenderHost

        anchors.fill: parent
        visible: true
        opacity: 0
        enabled: false
        z: hiddenZ
    }

    // 背景（余白部分）は黒
    Rectangle {
        anchors.fill: parent
        color: "black"
        z: -2
    }

    // プレビューコンテナ（アスペクト比維持）
    View3D {
        id: view

        // プロジェクト設定の解像度を取得（未設定時はFHD）
        property int projW: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.width : 1920
        property int projH: (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.height : 1080
        // アスペクト比計算
        property double aspect: projW / projH
        // 現在のクリップ内での相対時間 (0.0 ~ 1.0)
        // 他のコンポーネントから参照される可能性を考慮して定義
        property double currentClipTimeRatio: (TimelineBridge && TimelineBridge.transport) ? Math.max(0, Math.min(1, (TimelineBridge.transport.currentFrame - TimelineBridge.clipStartFrame) / TimelineBridge.clipDurationFrames)) : 0

        camera: mainCamera
        // 親に収まる最大サイズを計算 (Letterboxing)
        width: Math.min(parent.width, parent.height * aspect)
        height: Math.min(parent.height, parent.width / aspect)
        anchors.centerIn: parent
        focus: true
        Keys.onSpacePressed: {
            if (TimelineBridge && TimelineBridge.transport)
                TimelineBridge.transport.togglePlay();

        }

        // プロジェクト領域の背景
        Rectangle {
            anchors.fill: parent
            color: "#0a0a0a"
            z: -1
        }

        // カメラ設定 (必須)
        PerspectiveCamera {
            id: mainCamera

            property real distance: view.projH / (2 * Math.tan(fieldOfView * Math.PI / 360))

            // 動的カメラ距離計算: projH/2 / tan(fieldOfView/2)
            fieldOfView: 30
            position: Qt.vector3d(0, 0, distance)
            clipFar: 5000
        }

        DirectionalLight {
            eulerRotation.x: -30
            z: 1000
        }

        // プロジェクトの枠線（解像度ガイド）
        Node {
            // 画面中央を (0,0) としたときの枠
            Model {
                source: "#Rectangle"
                scale: Qt.vector3d((TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.width / 100 : 19.2, (TimelineBridge && TimelineBridge.project) ? TimelineBridge.project.height / 100 : 10.8, 1)
                position: Qt.vector3d(0, 0, -10)
                visible: false // 邪魔なので一旦隠す

                materials: DefaultMaterial {
                    // 枠線だけ表示したいが、簡易的に半透明の黒背景として表示
                    diffuseColor: "#22000000"
                }
                // 奥に配置

            }

        }

        // Instantiator の親となるノード
        Node {
            id: sceneRoot
        }

        // 動的オブジェクト生成用
        Instantiator {
            // QVariantListではなく、C++のAbstractListModelを使用
            model: TimelineBridge ? TimelineBridge.clipModel : null
            onObjectAdded: (index, object) => {
                object.parent = sceneRoot;
            }
            onObjectRemoved: (index, object) => {
                object.parent = null;
            }

            delegate: Node {
                id: clipNode

                // FB 収集用: BaseObject が参照できるよう layer を公開
                property int clipLayerRole: model.layer
                property Item fbRendererOutput: null // NodeLoader 完了後に接続
                // モデルロールから直接値を取得
                // パラメータを一度だけ取得してキャッシュ (undefinedチェックのオーバーヘッド削減)
                readonly property var p: model.params || {
                }
                readonly property real px: p.x || 0
                readonly property real py: p.y || 0
                readonly property real pz: p.z || 0
                readonly property real pRotX: p.rotationX || 0
                readonly property real pRotY: p.rotationY || 0
                readonly property real pRotZ: p.rotationZ || 0
                readonly property real pScale: p.scale || 100
                readonly property real pAspect: p.aspect || 0
                readonly property real pOpacity: p.opacity || 1
                // 拡大率と縦横比
                readonly property real baseScale: pScale * 0.01
                readonly property real aspectX: pAspect >= 0 ? (1 + pAspect) : 1
                readonly property real aspectY: pAspect < 0 ? (1 - pAspect) : 1

                function dbg(msg) {
                    Logger.log("[CompositeView][clipId=" + model.id + "][type=" + model.type + "] " + msg, TimelineBridge);
                }

                // レイヤーが非表示の場合は描画しない
                visible: {
                    return root.getLayerVisible(model.layer);
                }
                // 座標変換: 中心(0,0)、Y軸下プラス(AviUtl互換)
                // Qt3DはY上がプラスなので、入力を反転させる
                x: px
                y: -py
                z: pz + (model.layer * 5)
                // 中心座標 (Pivot)
                pivot: Qt.vector3d(p.anchorX || 0, -(p.anchorY || 0), p.anchorZ || 0)
                // 3軸回転
                eulerRotation.x: pRotX
                eulerRotation.y: -pRotY
                eulerRotation.z: -pRotZ
                scale.x: baseScale * aspectX
                scale.y: baseScale * aspectY
                scale.z: baseScale
                // 不透明度 (全体)
                opacity: pOpacity
                // params 変化 (scale/pos/rot/opacity) → BaseObject の fbCaptureItem を同期
                onPxChanged: objectContainer._syncTransformToItem()
                onPyChanged: objectContainer._syncTransformToItem()
                onPRotZChanged: objectContainer._syncTransformToItem()
                onBaseScaleChanged: objectContainer._syncTransformToItem()
                onAspectXChanged: objectContainer._syncTransformToItem()
                onAspectYChanged: objectContainer._syncTransformToItem()
                onPOpacityChanged: objectContainer._syncTransformToItem()

                // Loader (2D) は 3D シーン内では機能しないため、
                // Qt.createComponent を使用して Node 派生クラスを動的に生成する
                Common.NodeLoader {
                    id: objectContainer

                    // clipNode の transform が変わるたびに BaseObject へ同期
                    function _syncTransformToItem() {
                        if (!item)
                            return ;

                        if ("clipNodeScaleX" in item)
                            item.clipNodeScaleX = clipNode.baseScale * clipNode.aspectX;

                        if ("clipNodeScaleY" in item)
                            item.clipNodeScaleY = clipNode.baseScale * clipNode.aspectY;

                        if ("clipNodePosX" in item)
                            item.clipNodePosX = clipNode.px;

                        if ("clipNodePosY" in item)
                            item.clipNodePosY = clipNode.py;

                        if ("clipNodeRotZ" in item)
                            item.clipNodeRotZ = clipNode.pRotZ;

                        if ("clipNodeOpacity" in item)
                            item.clipNodeOpacity = clipNode.pOpacity;

                    }

                    source: model.qmlSource || ""
                    properties: {
                        "opacity": clipNode.pOpacity,
                        "clipId": model.id,
                        "clipStartFrame": model.startFrame,
                        "clipDurationFrames": model.durationFrames,
                        "renderHost": offscreenRenderHost,
                        "clipParams": Qt.binding(function() {
                            return model.params || {
                            };
                        })
                    }
                    componentFactory: root.getCachedComponent
                    // NodeLoader 完了後に fbRendererOutput を clipNode へ接続
                    onItemChanged: {
                        // FB専用プロパティは FrameBufferObject にのみ注入
                        if (item) {
                            // fbCaptureItem は BaseObject の property alias として公開済み
                            clipNode.fbRendererOutput = item.fbCaptureItem ?? null;
                            // clipLayer と sceneRootRef は FB のみが持つプロパティ
                            if (typeof item.clipLayer !== "undefined")
                                item.clipLayer = model.layer;

                            if (typeof item.sceneRootRef !== "undefined")
                                item.sceneRootRef = sceneRoot;

                            // 変換パラメータを注入 (初期値)
                            _syncTransformToItem();
                        }
                    }
                }

            }

        }

        environment: SceneEnvironment {
            id: sceneEnv

            backgroundMode: SceneEnvironment.Color
            clearColor: "#000000"
            antialiasingMode: SceneEnvironment.MSAA
            antialiasingQuality: SceneEnvironment.High
        }

    }

}

import QtQuick 2.15
import QtQuick.Controls 2.15
import QtQuick.Dialogs 6.3
import QtQuick.Layouts 1.15
import Rina.Core 1.0 // C++で登録したモジュール

Dialog {
    id: root

    property string selectedFile: ""
    // プロジェクト設定へのショートカット
    readonly property var project: TimelineBridge ? TimelineBridge.project : null
    readonly property int pWidth: project ? project.width : 1920
    readonly property int pHeight: project ? project.height : 1080
    // ProjectServiceはfps(double)を持っているので、そこから簡易的にnum/denを作る
    readonly property double pFps: project ? project.fps : 60
    readonly property int pFpsNum: Math.round(pFps * 1000)
    readonly property int pFpsDen: 1000

    title: "メディアの書き出し"
    modal: true
    width: 600
    height: 400
    standardButtons: Dialog.Ok | Dialog.Cancel
    onAccepted: {
        if (filePathField.text === "")
            return ;

        var codec = codecCombo.currentIndex === 0 ? "h264_vaapi" : "libx264";
        var bitrateVal = bitrateSpin.value * 1e+06;
        console.log("Starting Export: " + root.pWidth + "x" + root.pHeight + " @ " + codec);
        // C++側の処理を開始
        encoder.open({
            "width": root.pWidth,
            "height": root.pHeight,
            "fps_num": root.pFpsNum,
            "fps_den": root.pFpsDen,
            "bitrate": bitrateVal,
            "codecName": codec,
            "outputUrl": filePathField.text
        });
        // 先に閉じる (UIの重なりを防ぐ & UIスレッドを身軽にする)
        root.close();
        // 少し待ってから開始 (閉じるアニメーションの完了待ち)
        var timer = Qt.createQmlObject("import QtQuick 2.0; Timer { interval: 200; repeat: false; running: true; }", root);
        timer.triggered.connect(function() {
            if (TimelineBridge)
                TimelineBridge.exportVideoHW(encoder);

        });
    }

    // C++のエンコーダーインスタンス
    VideoEncoder {
        id: encoder
    }

    // ファイル保存ダイアログ
    FileDialog {
        id: fileDialog

        title: "保存先を指定"
        fileMode: FileDialog.SaveFile
        nameFilters: ["MP4 Video (*.mp4)", "MKV Video (*.mkv)", "All files (*)"]
        onAccepted: {
            root.selectedFile = fileDialog.selectedFile;
            // file:/// prefixを除去 (Linux/Windows対応)
            var path = root.selectedFile.toString();
            if (Qt.platform.os === "windows")
                path = path.replace(/^(file:\/{3})/, "");
            else
                path = path.replace(/^(file:\/\/)/, "");
            filePathField.text = path;
        }
    }

    ColumnLayout {
        anchors.fill: parent
        anchors.margins: 20
        spacing: 15

        RowLayout {
            TextField {
                id: filePathField

                Layout.fillWidth: true
                placeholderText: "保存先ファイルパス..."
                text: root.selectedFile
            }

            Button {
                text: "参照..."
                onClicked: fileDialog.open()
            }

        }

        // エンコード設定情報
        GroupBox {
            title: "出力設定 (プロジェクト設定同期)"
            Layout.fillWidth: true

            GridLayout {
                columns: 2
                rowSpacing: 10
                columnSpacing: 20

                Label {
                    text: "解像度:"
                }

                Label {
                    text: root.pWidth + " x " + root.pHeight
                    font.bold: true
                }

                Label {
                    text: "フレームレート:"
                }

                Label {
                    text: root.pFps.toFixed(2) + " fps"
                    font.bold: true
                }

                Label {
                    text: "コーデック:"
                }

                ComboBox {
                    id: codecCombo

                    model: ["h264_vaapi (Hardware)", "libx264 (Software)"]
                    currentIndex: 0
                }

                Label {
                    text: "品質 (Bitrate):"
                }

                SpinBox {
                    id: bitrateSpin

                    from: 1
                    to: 100
                    value: 15 // Mbps
                    editable: true
                    stepSize: 1
                    // suffixプロパティの代替実装
                    textFromValue: function(value, locale) {
                        return value + " Mbps";
                    }
                    valueFromText: function(text, locale) {
                        return Number.fromLocaleString(locale, text.replace(" Mbps", ""));
                    }
                }

            }

        }

        // Spacer
        Item {
            Layout.fillHeight: true
        }

    }

}

