    property int currentFrames: 0 // 既存のフレーム数を保持するためのプロパティ

    function openForScene(sceneId, name, w, h, fps, frames) {
        targetSceneId = sceneId;
        nameField.text = name;
        widthField.value = w;
        heightField.value = h;
        fpsField.value = Math.round(fps * 100);
        currentFrames = frames;
        root.show();
        root.raise();
        root.requestActivate();
    }

    title: "シーン設定"
    width: 450
    height: 300

    ColumnLayout {
        anchors.fill: parent
        anchors.margins: 15
        spacing: 10

        RowLayout {
            Label {
                text: "シーン名:"
                Layout.preferredWidth: 100
            }

            TextField {
                id: nameField

                Layout.fillWidth: true
                selectByMouse: true
            }

        }

        RowLayout {
            Label {
                text: "幅:"
                Layout.preferredWidth: 100
            }

            SpinBox {
                id: widthField

                from: 1
                to: 8000
                editable: true
                Layout.fillWidth: true
            }

        }

        RowLayout {
            Label {
                text: "高さ:"
                Layout.preferredWidth: 100
            }

            SpinBox {
                id: heightField

                from: 1
                to: 8000
                editable: true
                Layout.fillWidth: true
            }

        }

        RowLayout {
            Label {
                text: "FPS:"
                Layout.preferredWidth: 100
            }

            SpinBox {
                id: fpsField

                property real realValue: value / 100

                from: 100
                to: 24000
                stepSize: 100
                editable: true
                Layout.fillWidth: true
                textFromValue: function(value, locale) {
                    return (value / 100).toFixed(2);
                }
                valueFromText: function(text, locale) {
